pub use crate::iter::ParallelIterator;

use crate::range::RangeProducer;
use crate::slice::{ChunksMutProducer, SliceMutProducer, SliceProducer};

pub trait IntoParallelIterator {
    type Iter: ParallelIterator<Item = Self::Item>;
    type Item: Send;
    fn into_par_iter(self) -> Self::Iter;
}

pub trait IntoParallelRefIterator<'data> {
    type Iter: ParallelIterator<Item = Self::Item>;
    type Item: Send + 'data;
    fn par_iter(&'data self) -> Self::Iter;
}

pub trait IntoParallelRefMutIterator<'data> {
    type Iter: ParallelIterator<Item = Self::Item>;
    type Item: Send + 'data;
    fn par_iter_mut(&'data mut self) -> Self::Iter;
}

pub trait ParallelSliceMut<T: Send> {
    fn par_chunks_mut(&mut self, chunk_size: usize) -> ParChunksMut<'_, T>;
}

// -----------------------------------------------------------------------------
// Wrapper Implementation Structs
// -----------------------------------------------------------------------------

pub struct ParSlice<'data, T> {
    slice: &'data [T],
}

impl<'data, T: Send + Sync> ParallelIterator for ParSlice<'data, T> {
    type Item = &'data T;
    type Producer = SliceProducer<'data, T>;

    fn into_producer(self) -> Self::Producer {
        SliceProducer { slice: self.slice }
    }
}

pub struct ParSliceMut<'data, T> {
    slice: &'data mut [T],
}

impl<'data, T: Send> ParallelIterator for ParSliceMut<'data, T> {
    type Item = &'data mut T;
    type Producer = SliceMutProducer<'data, T>;

    fn into_producer(self) -> Self::Producer {
        SliceMutProducer { slice: self.slice }
    }
}

pub struct ParRange {
    start: usize,
    end: usize,
}

impl ParallelIterator for ParRange {
    type Item = usize;
    type Producer = RangeProducer;

    fn into_producer(self) -> Self::Producer {
        RangeProducer {
            start: self.start,
            end: self.end,
        }
    }
}

pub struct ParChunksMut<'data, T> {
    slice: &'data mut [T],
    chunk_size: usize,
}

impl<'data, T: Send> ParallelIterator for ParChunksMut<'data, T> {
    type Item = &'data mut [T];
    type Producer = ChunksMutProducer<'data, T>;

    fn into_producer(self) -> Self::Producer {
        ChunksMutProducer {
            slice: self.slice,
            chunk_size: self.chunk_size,
        }
    }
}

// -----------------------------------------------------------------------------
// Trait Implementations for Standard Types
// -----------------------------------------------------------------------------

impl<'data, T: Send + Sync + 'data> IntoParallelRefIterator<'data> for [T] {
    type Iter = ParSlice<'data, T>;
    type Item = &'data T;

    fn par_iter(&'data self) -> Self::Iter {
        ParSlice { slice: self }
    }
}

impl<'data, T: Send + Sync + 'data> IntoParallelRefIterator<'data> for Vec<T> {
    type Iter = ParSlice<'data, T>;
    type Item = &'data T;

    fn par_iter(&'data self) -> Self::Iter {
        ParSlice {
            slice: self.as_slice(),
        }
    }
}

impl<'data, T: Send + 'data> IntoParallelRefMutIterator<'data> for [T] {
    type Iter = ParSliceMut<'data, T>;
    type Item = &'data mut T;

    fn par_iter_mut(&'data mut self) -> Self::Iter {
        ParSliceMut { slice: self }
    }
}

impl<'data, T: Send + 'data> IntoParallelRefMutIterator<'data> for Vec<T> {
    type Iter = ParSliceMut<'data, T>;
    type Item = &'data mut T;

    fn par_iter_mut(&'data mut self) -> Self::Iter {
        ParSliceMut {
            slice: self.as_mut_slice(),
        }
    }
}

impl IntoParallelIterator for std::ops::Range<usize> {
    type Iter = ParRange;
    type Item = usize;

    fn into_par_iter(self) -> Self::Iter {
        ParRange {
            start: self.start,
            end: self.end,
        }
    }
}

impl<T: Send> ParallelSliceMut<T> for [T] {
    fn par_chunks_mut(&mut self, chunk_size: usize) -> ParChunksMut<'_, T> {
        ParChunksMut {
            slice: self,
            chunk_size,
        }
    }
}
